164→  lines: Array<string>
165→): Array<{ text: string; position: number }> {
166→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
167→
168→  for (let i = 0; i < lines.length; i++) {
169→    const trimmed = lines[i].trim();
170→    if (trimmed.length > 0) {
171→      nonEmptyLines.push({ text: trimmed, index: i });
172→    }
173→  }
174→
175→  const burstEnd = findBurstEnd(nonEmptyLines);
176→  const candidates: Array<{ text: string; position: number }> = [];
177→  const seen = new Set<string>();
178→
179→  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
180→    const line = nonEmptyLines[i];
181→
182→    // Single line
183→    if (passesHardFilters(line.text)) {
184→      const norm = line.text.toLowerCase();
185→      if (!seen.has(norm)) {
186→        seen.add(norm);
187→        candidates.push({ text: line.text, position: line.index });
188→      }
189→    }
190→
191→    // 2-line join
192→    if (i + 1 < nonEmptyLines.length) {
193→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
194→      if (passesHardFilters(joined2)) {
195→        const norm = joined2.toLowerCase();
196→        if (!seen.has(norm)) {
197→          seen.add(norm);
198→          candidates.push({ text: joined2, position: line.index });
199→        }
200→      }
201→    }
202→
203→    // 3-line join
204→    if (i + 2 < nonEmptyLines.length) {
205→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
206→      if (passesHardFilters(joined3)) {
207→        const norm = joined3.toLowerCase();
208→        if (!seen.has(norm)) {
209→          seen.add(norm);
210→          candidates.push({ text: joined3, position: line.index });
211→        }
212→      }
213→    }
214→  }
215→
216→  // Pre-filter to 25 before embedding calls: prefer ALL_CAPS and short candidates.
217→  // Position-based scoring handles final ranking.
218→  if (candidates.length > 25) {
219→    const prioritized = candidates.slice().sort((a, b) => {
220→      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
221→      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
222→      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
223→      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
224→      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
225→      return aShort - bShort;
226→    });
227→    return prioritized.slice(0, 25);
228→  }
229→
230→  return candidates;
231→}
232→
233→// Module-level cache for reference embeddings
234→let cachedTitleRefEmbedding: Array<number> | null = null;
235→let cachedHeaderRefEmbedding: Array<number> | null = null;
236→let cachedNoiseRefEmbedding: Array<number> | null = null;
237→
238→export function _resetEmbeddingCacheForTests(): void {
239→  cachedTitleRefEmbedding = null;
240→  cachedHeaderRefEmbedding = null;
241→  cachedNoiseRefEmbedding = null;
242→}
243→
244→export async function extractTitleWithEmbeddings(
245→  text: string,
246→  embed: EmbedFn
247→): Promise<string | undefined> {
248→  if (!text || text.trim().length === 0) {
249→    return undefined;
250→  }
251→
252→  const lines = text.split("\n");
253→  const candidates = buildCandidates(lines);
254→
255→  if (candidates.length === 0) {
256→    return undefined;
257→  }
258→
259→  // Cache reference embeddings
260→  if (!cachedTitleRefEmbedding) {
261→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
262→  }
263→  if (!cachedHeaderRefEmbedding) {
264→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
265→  }
266→  if (!cachedNoiseRefEmbedding) {
267→    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
268→  }
269→
270→  // Find the first ALL_CAPS candidate with ≥2 words where every significant word has ≥4 alpha letters.
271→  // Insignificant tokens (≤1 alpha letter: "/", "&", "+", ":", "D)", etc.) are filtered before
272→  // the check so that multi-line joins with continuation punctuation still qualify.
273→  const isStructuralHeading = (c: { text: string }): boolean => {
274→    if (!isAllCaps(c.text) || wordCount(c.text) < 2) return false;
275→    const sigWords = c.text.trim().split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length > 1);
276→    return sigWords.length >= 2 && sigWords.every((w) => w.replace(/[^A-Z]/g, "").length >= 4);
277→  };
278→  const baseHeading = candidates.find(isStructuralHeading);
279→  // When the initial heading has a continuation on the next line introduced by a punctuation token
280→  // (/, &, +, :, or parenthesis), prefer the longer 2-line join as the complete heading.
281→  // E.g. "SAFFRON WHEAT BUNS WITH QUARK" + "/ COTTAGE CHEESE (VARIATION D)" → prefers the join.
282→  // Guard: the remainder after the prefix must start with a continuation character to avoid
283→  // merging two separate consecutive recipe titles (FINNISH MILK FLATBREADS stays separate
284→  // from FINNISH POTATO FLATBREADS because "FINNISH" does not start with a continuation token).
285→  const firstStructuralHeading = baseHeading && (
286→    candidates.find((c) => {
287→      if (!isStructuralHeading(c)) return false;
288→      const hLower = baseHeading.text.toLowerCase();
289→      const cLower = c.text.toLowerCase();
290→      return cLower.startsWith(hLower + " ") && /^[/&+:(]/.test(cLower.slice(hLower.length + 1));
291→    }) ?? baseHeading
292→  );
293→
294→  const scored: Array<{ text: string; position: number; score: number; rawScore: number; baseScore: number }> = [];
295→
296→  for (const candidate of candidates) {
297→    const embedding = await embed(candidate.text);
298→    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
299→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
300→    const noiseSim = cosineSimilarity(embedding, cachedNoiseRefEmbedding);
301→    const rawScore = titleSim - Math.max(headerSim, noiseSim);
302→
303→    // Position factor: multiplicative tiebreaker — amplifies existing signal, doesn't replace it
304→    const relativePosition = candidate.position / lines.length;
305→    const positionFactor = relativePosition < 0.5
306→      ? 1.0 + 0.12 * (1 - relativePosition * 2)
307→      : 1.0;
308→
309→    // ALL_CAPS bonus: recipe books use ALL_CAPS for titles and section headings
310→    const allCapsBonus = isAllCaps(candidate.text) && candidate.text.replace(/[^a-zA-Z]/g, "").length >= 4
311→      ? 0.08
312→      : 0;
313→
314→    // Structural heading bonus: first clean ALL_CAPS heading is almost always the recipe title
315→    const structuralBonus =
316→      firstStructuralHeading && candidate === firstStructuralHeading ? 0.10 : 0;
317→
318→    // baseScore excludes position factor — used for threshold so position boost on the first
319→    // title doesn't inflate the bar and exclude valid later titles on multi-recipe pages
320→    const baseScore = rawScore + allCapsBonus + structuralBonus;
321→    const score = rawScore * positionFactor + allCapsBonus + structuralBonus;
322→    scored.push({ text: candidate.text, position: candidate.position, score, rawScore, baseScore });
323→  }
324→
325→  if (scored.length === 0) {
326→    return undefined;
327→  }
328→
329→  // Use position-free baseScore for threshold so position boost on the first title doesn't
330→  // inflate the bar and exclude valid later titles on multi-recipe pages.
331→  const bestBaseScore = Math.max(...scored.map((s) => s.baseScore));
332→  const threshold = Math.max(0.08, bestBaseScore * 0.7);
333→
334→  // Filter candidates above threshold
335→  let selected = scored.filter((s) => s.score >= threshold);
336→
337→  // Remove word-boundary prefixes of firstStructuralHeading when the heading itself survived
338→  // the threshold. Cases:
339→  //   ARAYES case:  firstStructuralHeading = "ARAYES SHRAK" (2-word join qualifies; "ARAYES"
340→  //     alone = 1 word, so it never qualified). Filter removes "ARAYES" so dedup keeps the join.
341→  //   SAFFRON case: baseHeading was the partial line; continuation logic above upgraded
342→  //     firstStructuralHeading to the full join. Filter removes the partial so dedup keeps join.
343→  // Safety: only fires when the complete heading itself is in selected (passed the threshold).
344→  if (firstStructuralHeading && selected.some((s) => s.text === firstStructuralHeading.text)) {
345→    const fshLower = firstStructuralHeading.text.toLowerCase();
346→    selected = selected.filter((s) => {
347→      if (s.text === firstStructuralHeading.text) return true;
348→      const sLower = s.text.toLowerCase();
349→      // Remove s if it is a space-delimited prefix of the structural heading
350→      return !fshLower.startsWith(sLower + " ");
351→    });
352→  }
353→
354→  // Deduplicate: if one title is a substring of another, keep the shorter (more focused) one.
355→  // DO NOT CHANGE THIS LOGIC — it has been incorrectly "improved" by the title-loop 5 times.
356→  // The tests require shorter wins: "Pierogi Ruskie" over "Pierogi Ruskie 200g mąki 3 ziemniaki".
357→  // The pre-filter above handles the conflicting case (structural heading prefix removal) so that
358→  // the incomplete prefix line is never present here when the complete join is in selected.
359→  selected = selected.filter((a) => {
360→    const aLower = a.text.toLowerCase();
361→    return !selected.some(
362→      (b) =>
363→        b !== a &&
364→        aLower.includes(b.text.toLowerCase()) &&
365→        b.text.length < a.text.length
366→    );
367→  });
368→
369→  // Multi-title guard: only join multiple candidates with "+" when there is
370→  // structural evidence of a multi-recipe page (≥2 ALL_CAPS headings).
371→  // A single ALL_CAPS title among mixed-case survivors is a single-recipe page —
372→  // collapse to the highest-scoring candidate.
373→  // Zero ALL_CAPS survivors → mixed-case multi-title page → keep all.
374→  if (selected.length > 1) {
375→    const allCapsSelected = selected.filter((s) => isAllCaps(s.text));
376→    if (allCapsSelected.length >= 2) {
377→      selected = allCapsSelected;
378→    } else if (allCapsSelected.length === 1) {
379→      selected = [selected.reduce((a, b) => (a.score > b.score ? a : b))];
380→    }
381→  }
382→
383→  // Cap at 3, sort by document position
384→  selected.sort((a, b) => a.position - b.position);
385→  selected = selected.slice(0, 3);
386→
387→  if (selected.length === 0) {
388→    return undefined;
389→  }
390→
391→  return selected.map((s) => s.text).join(" + ");
392→}
393→
394→/**
395→ * Extract potential recipe title from OCR text (sync heuristic fallback)
396→ */
397→export function extractTitle(text: string): string | undefined {
398→  if (!text || text.trim().length === 0) {
399→    return undefined;
400→  }
401→
402→  const lines = text.split("\n").map((line) => line.trim());
403→
404→  for (const line of lines) {
405→    if (line.length === 0) continue;
406→    if (line.length < 3 || line.length > 50) continue;
407→    if (looksLikeIngredient(line)) continue;
408→    if (isAllCaps(line)) continue;
409→    if (startsWithNumber(line)) continue;
410→    return line;
411→  }
412→
413→  return undefined;
414→}
